// src/services/api.js
import axios from "axios";

// Create a dedicated Axios instance so baseURL and headers are centralized. [18]
const api = axios.create({
  baseURL: process.env.REACT_APP_API_URL || "http://localhost:5000/api",
  headers: { "Content-Type": "application/json" },
}); // [18][13]

// Attach Authorization: Bearer <token> to every request via an interceptor. [1][2]
api.interceptors.request.use(
  (config) => {
    const token = localStorage.getItem("nfxtoken");
    if (token) {
      // Ensure headers exists and set the Authorization header. [3][11]
      config.headers = config.headers || {};
      config.headers.Authorization = `Bearer ${token}`;
    }
    return config;
  },
  (error) => Promise.reject(error)
); // [2][11]

// Optional: basic 401 handling (kept simple; expand to refresh if needed). [11]
api.interceptors.response.use(
  (res) => res,
  (err) => {
    if (err?.response?.status === 401) {
      // Token missing/expired: clear and optionally redirect on the UI. [11]
      // localStorage.removeItem("nfxtoken");
    }
    return Promise.reject(err);
  }
); // [11]

// ---------- Auth APIs ----------

// POST /auth/login -> { token, user?... } and persist token. [7]
export const loginUser = async ({ email, password }) => {
  const res = await api.post("/auth/login", { email, password });
  if (res?.data?.token) {
    localStorage.setItem("nfxtoken", res.data.token);
  }
  return res.data;
}; // [7]

// POST /auth/register (adjust fields to backend contract). [7]
export const signupUser = async ({ name, email, password }) => {
  const res = await api.post("/auth/register", { name, email, password });
  return res.data;
}; // [7]

// Utility to clear token on logout. [2]
export const logoutUser = () => localStorage.removeItem("nfxtoken"); // [2]

// ---------- Vehicle APIs ----------

// GET /vehicles -> array. [7]
export const listVehicles = async () => {
  const res = await api.get("/vehicles");
  return res.data;
}; // [7]

// POST /vehicles -> created item; payload supports either camelCase or snake_case fields as backend expects. [7]
export const createVehicle = async (payload) => {
  const res = await api.post("/vehicles", payload);
  return res.data;
}; // [7]

export default api;
